import { Request, Response, NextFunction } from 'express';
import { GroupService } from './group.service';
import { GroupValidator } from './group.validator';
import { CreateGroupDto } from './group.dto';
import { createLogger } from '../../utils/logger';

const logger = createLogger('group.controller');

export class GroupController {
  constructor(private groupService: GroupService) {}

  async createGroup(req: Request, res: Response, next: NextFunction): Promise<Response> {
    const { userId, body } = req;
    const validation = GroupValidator.validateCreateGroup(body);
    if (!validation.success) return next(validation.error);

    const createGroupDto: CreateGroupDto = validation.data;
    try {
      const group = await this.groupService.createGroup(userId, createGroupDto);
      return res.status(201).json({ success: true, data: group });
    } catch (err) {
      logger.error(`Error creating group: ${err}`);
      return next(err);
    }
  }
}

import { GroupRepository } from './group.repository';
import { CreateGroupDto } from './group.dto';
import { AppError } from '../../utils/error';
import { ObjectId } from 'mongodb';

export class GroupService {
  constructor(private groupRepository: GroupRepository) {}

  async createGroup(adminId: string, createGroupDto: CreateGroupDto) {
    try {
      const groupId = new ObjectId();
      const group = await this.groupRepository.create({
        id: groupId,
        adminId: new ObjectId(adminId),
        ...createGroupDto,
      });
      return group;
    } catch (err) {
      throw new AppError('GROUP_CREATION_FAILED', `Failed to create group with admin ID: ${adminId}`);
    }
  }
}

import { Db, Collection } from 'mongodb';
import { Group } from '../../types/group.interface';

export class GroupRepository {
  private collection: Collection<Group>;

  constructor(db: Db) {
    this.collection = db.collection('groups');
  }

  async create(group: Group): Promise<Group> {
    await this.collection.insertOne(group);
    return group;
  }
}

import { z } from 'zod';

export const CreateGroupDto = z.object({
  name: z.string().min(1),
  description: z.string().optional(),
  members: z.array(z.string().uuid()).optional(),
  telegramChatId: z.string().optional(),
});

export type CreateGroupDto = z.infer<typeof CreateGroupDto>;

import { CreateGroupDto } from './group.dto';
import { ZodError } from 'zod';

export class GroupValidator {
  static validateCreateGroup(input: unknown): { success: boolean; data?: CreateGroupDto; error?: ZodError } {
    const result = CreateGroupDto.safeParse(input);
    if (result.success) return { success: true, data: result.data };
    return { success: false, error: result.error };
  }
}

import { ObjectId } from 'mongodb';

export interface Group {
  id: ObjectId;
  name: string;
  description?: string;
  adminId: ObjectId;
  members: ObjectId[];
  telegramChatId?: string;
  createdAt: Date;
}

import { createLogger, format, transports } from 'winston';

export const createLogger = (module: string) => {
  return createLogger({
    level: 'info',
    format: format.combine(
      format.timestamp(),
      format.printf(({ timestamp, level, message }) => {
        return `${timestamp} [${level}]: (${module}) ${message}`;
      })
    ),
    transports: [new transports.Console()]
  });
};

export class AppError extends Error {
  statusCode: number;
  code: string;

  constructor(code: string, message: string, statusCode: number = 500) {
    super(message);
    this.code = code;
    this.statusCode = statusCode;
  }
}
